import { BrushTool, cursors } from '@cornerstonejs/tools';
import type { PublicToolProps, ToolProps } from '@cornerstonejs/tools/types';
import { getEnabledElement } from '@cornerstonejs/core';
import type { Types } from '@cornerstonejs/core';
import { StrategyCallbacks } from '@cornerstonejs/tools/enums';
import { EventTypes, SVGDrawingHelper } from '@cornerstonejs/tools/types';
import triggerAnnotationRenderForViewportUIDs from '@cornerstonejs/tools/utilities/triggerAnnotationRenderForViewportIds';
import { vec3 } from 'gl-matrix';
import { drawing } from '@cornerstonejs/tools';
import pako from 'pako';
import { servicesManager } from '../../../../platform/app/src/App';

class CustomBrushTool extends BrushTool {
  private backgroundLocked: boolean;

  constructor(toolProps: PublicToolProps, defaultToolProps: ToolProps) {
    super(toolProps, defaultToolProps);
    this.backgroundLocked = false;

    this._endCallback = evt => {
      // End callback of BrushTool
      const eventData = evt.detail;
      const { element } = eventData;
      const enabledElement = getEnabledElement(element);
      const operationData = this.getOperationData(element);
      if (!this._previewData.preview && !this._previewData.isDrag) {
        this.applyActiveStrategy(enabledElement, operationData);
      }
      this._deactivateDraw(element);
      cursors.elementCursor.resetElementCursor(element);
      this.updateCursor(evt);
      this._editData = null;
      this.applyActiveStrategyCallback(
        enabledElement,
        operationData,
        StrategyCallbacks.OnInteractionEnd
      );
      if (!this._previewData.isDrag) {
        this.acceptPreview(element);
      }

      // Save the segmentation in databaseService
      const { databaseService, segmentationService } = servicesManager.services;
      const { viewport } = enabledElement;
      const { segmentationId } = segmentationService.getActiveSegmentation(viewport.id);
      if (segmentationId === 'anatomy') {
        const { voxelManager } = segmentationService.getLabelmapVolume(segmentationId);
        const anatomyVolumeArray = pako.deflate(voxelManager.getCompleteScalarDataArray());
        databaseService.modifyAnalysisSegmentedAnatomy(anatomyVolumeArray);
      } else if (segmentationId === 'diseases') {
        const { voxelManager } = segmentationService.getLabelmapVolume(segmentationId);
        const diseasesVolumeArray = pako.deflate(voxelManager.getCompleteScalarDataArray());
        databaseService.modifyAnalysisSegmentedDiseases(diseasesVolumeArray);
      }
    };
  }

  private createHoverData(element, centerCursorInWorld?) {
    const enabledElement = getEnabledElement(element);
    const { viewport } = enabledElement;

    const camera = viewport.getCamera();
    const { viewPlaneNormal, viewUp } = camera;

    const viewportIdsToRender = [viewport.id];

    const { segmentIndex, segmentationId, segmentColor } =
      this.getActiveSegmentationData(viewport) || {};

    // Center of circle in canvas Coordinates
    const brushCursor = {
      metadata: {
        viewPlaneNormal: <Types.Point3>[...viewPlaneNormal],
        viewUp: <Types.Point3>[...viewUp],
        FrameOfReferenceUID: viewport.getFrameOfReferenceUID(),
        referencedImageId: '',
        toolName: this.getToolName(),
        segmentColor,
      },
      data: {},
    };

    return {
      brushCursor,
      centerCursorInWorld,
      segmentIndex,
      viewport,
      segmentationId,
      segmentColor,
      viewportIdsToRender,
    };
  }

  protected updateCursor(evt: EventTypes.InteractionEventType) {
    const eventData = evt.detail;
    const { element } = eventData;
    const { currentPoints } = eventData;
    const centerCursorInWorld = currentPoints.world;
    this._hoverData = this.createHoverData(element, centerCursorInWorld);

    this._calculateCursor(element, centerCursorInWorld);

    if (!this._hoverData) {
      return;
    }

    triggerAnnotationRenderForViewportUIDs(this._hoverData.viewportIdsToRender);
  }

  protected getOperationData(element?) {
    let editData = this._editData || this.createEditData(element);
    if (this.backgroundLocked) {
      // Lock background if needed
      editData = { ...editData, segmentsLocked: editData.segmentsLocked.concat(0) };
    }

    const { segmentIndex, segmentationId, brushCursor } =
      this._hoverData || this.createHoverData(element);
    const { data, metadata = {} } = brushCursor || {};
    const { viewPlaneNormal, viewUp } = metadata;
    const operationData = {
      ...editData,
      points: data?.handles?.points,
      segmentIndex,
      previewColors: this.configuration.preview.enabled
        ? this.configuration.preview.previewColors
        : null,
      viewPlaneNormal,
      toolGroupId: this.toolGroupId,
      segmentationId,
      viewUp,
      strategySpecificConfiguration: this.configuration.strategySpecificConfiguration,
      // Provide the preview information so that data can be used directly
      preview: this._previewData?.preview,
    };
    return operationData;
  }

  private _calculateCursor(element, centerCursorInWorld) {
    const enabledElement = getEnabledElement(element);
    const { viewport } = enabledElement;
    const camera = viewport.getCamera();
    const { brushSize } = this.configuration;

    const viewUp = vec3.fromValues(camera.viewUp[0], camera.viewUp[1], camera.viewUp[2]);
    const viewPlaneNormal = vec3.fromValues(
      camera.viewPlaneNormal[0],
      camera.viewPlaneNormal[1],
      camera.viewPlaneNormal[2]
    );
    const viewRight = vec3.create();
    vec3.cross(viewRight, viewUp, viewPlaneNormal);

    const bottomCursorInWorld = vec3.create();
    const topCursorInWorld = vec3.create();
    const leftCursorInWorld = vec3.create();
    const rightCursorInWorld = vec3.create();

    // Calculate the bottom and top points of the circle in world coordinates
    for (let i = 0; i <= 2; i++) {
      bottomCursorInWorld[i] = centerCursorInWorld[i] - viewUp[i] * brushSize;
      topCursorInWorld[i] = centerCursorInWorld[i] + viewUp[i] * brushSize;
      leftCursorInWorld[i] = centerCursorInWorld[i] - viewRight[i] * brushSize;
      rightCursorInWorld[i] = centerCursorInWorld[i] + viewRight[i] * brushSize;
    }

    if (!this._hoverData) {
      return;
    }

    const { brushCursor } = this._hoverData;
    const { data } = brushCursor;

    if (data.handles === undefined) {
      data.handles = {};
    }

    data.handles.points = [
      bottomCursorInWorld,
      topCursorInWorld,
      leftCursorInWorld,
      rightCursorInWorld,
    ];

    const activeStrategy = this.configuration.activeStrategy;
    const strategy = this.configuration.strategies[activeStrategy];

    // Note: i don't think this is the best way to implement this
    // but don't think we have a better way to do it for now
    if (typeof strategy.computeInnerCircleRadius === 'function') {
      strategy.computeInnerCircleRadius({
        configuration: this.configuration,
        viewport,
      });
    }

    data.invalidated = false;
  }

  renderAnnotation(
    enabledElement: Types.IEnabledElement,
    svgDrawingHelper: SVGDrawingHelper
  ): void {
    if (!this._hoverData) {
      return;
    }

    const { viewport } = enabledElement;

    const viewportIdsToRender = this._hoverData.viewportIdsToRender;

    if (!viewportIdsToRender.includes(viewport.id)) {
      return;
    }

    const brushCursor = this._hoverData.brushCursor;

    if (brushCursor.data.invalidated === true) {
      const { centerCursorInWorld } = this._hoverData;
      const { element } = viewport;

      // This can be set true when changing the brush size programmatically
      // whilst the cursor is being rendered.
      this._calculateCursor(element, centerCursorInWorld);
    }

    const toolMetadata = brushCursor.metadata;
    if (!toolMetadata) {
      return;
    }

    const annotationUID = toolMetadata.brushCursorUID;

    const data = brushCursor.data;
    const { points } = data.handles;
    const canvasCoordinates = points.map(p => viewport.worldToCanvas(p));

    const bottom = canvasCoordinates[0];
    const top = canvasCoordinates[1];

    const center = [Math.floor((bottom[0] + top[0]) / 2), Math.floor((bottom[1] + top[1]) / 2)];

    const radius = Math.abs(bottom[1] - Math.floor((bottom[1] + top[1]) / 2));

    const color = `rgb(${toolMetadata.segmentColor?.slice(0, 3) || [0, 0, 0]})`;

    // If rendering engine has been destroyed while rendering
    if (!viewport.getRenderingEngine()) {
      console.warn('Rendering Engine has been destroyed');
      return;
    }

    const circleUID = '0';
    drawing.drawCircle(svgDrawingHelper, annotationUID, circleUID, center as Types.Point2, radius, {
      color,
    });

    const activeStrategy = this.configuration.activeStrategy;
    const { dynamicRadiusInCanvas } = this.configuration.strategySpecificConfiguration[
      activeStrategy
    ] || {
      dynamicRadiusInCanvas: 0,
    };

    if (dynamicRadiusInCanvas) {
      const circleUID1 = '1';
      drawing.drawCircle(
        svgDrawingHelper,
        annotationUID,
        circleUID1,
        center as Types.Point2,
        dynamicRadiusInCanvas,
        {
          color,
        }
      );
    }
  }
}

export default CustomBrushTool;
