import { DicomMetadataStore, PubSubService, Types as OhifTypes } from '@ohif/core';
import { CommandsManager } from 'platform/core/src/classes';
import {
  Configs,
  DiseasesCategories,
  JsonTranslation,
  PanoramicState,
} from '../../types/Panoramic';
import { generatePanoramic } from './../../../../default/src/Panels/PanoramicUtils/generatePanoramic';
import { getEnabledElement, StackViewport, utilities as csUtils } from '@cornerstonejs/core';
import {
  annotation as cstAnnotation,
  Enums as cstEnums,
  segmentation as cstSegmentation,
  Types as cstTypes,
  utilities as cstUtils,
} from '@cornerstonejs/tools';
import { Point3 } from '@cornerstonejs/core/types';
import { EventTypes } from '@cornerstonejs/tools/types';
import { VolumeData } from '../../types/CornerstoneCacheService';
import BrushTool from '../../tools/CustomBrushTool';

function waitCondition<T>(condition: () => T) {
  return new Promise<T>((resolve, reject) => {
    const wait = () => {
      const result = condition();
      if (result) {
        return resolve(result);
      } else {
        setTimeout(() => wait(), 50);
      }
    };
    wait();
  });
}

export default class PanoramicService extends PubSubService {
  private displayed: boolean = false;
  private editing: boolean = false;
  private processing: boolean = false;
  private subscriptions: any[] = [];
  private panoramicStates: { [displaySetUID: string]: PanoramicState } = {};
  private dentascanIndex: number = undefined;
  private comment: string = '';

  private readonly commandsManager: CommandsManager;
  private readonly servicesManager: AppTypes.ServicesManager;

  static EVENTS = {
    STATUS_DISPLAYED_CHANGED: 'event::PanoramicService:statusDisplayedChanged',
    STATUS_EDITING_CHANGED: 'event::PanoramicService:statusEditingChanged',
    PANORAMIC_STATE_UPDATED: 'event::PanoramicService:panoramicStateUpdated',
    PANORAMIC_PROCESSING: 'event::PanoramicService:panoramicProcessing',
    DENTASCAN_INDEX_UPDATED: 'event::PanoramicService:dentascanIndexUpdated',
    TEETH_AXES_UPDATED: 'event::PanoramicService:teethAxesUpdated',
  };

  public static REGISTRATION = {
    name: 'panoramicService',
    create: ({
      commandsManager,
      servicesManager,
    }: OhifTypes.Extensions.ExtensionParams): PanoramicService => {
      return new PanoramicService(commandsManager, servicesManager);
    },
  };

  constructor(commandsManager: CommandsManager, servicesManager: AppTypes.ServicesManager) {
    super(PanoramicService.EVENTS);
    this.commandsManager = commandsManager;
    this.servicesManager = servicesManager;
  }

  public isDisplayed = () => {
    return this.displayed;
  };

  public setDisplayed = (displayed: boolean) => {
    this.displayed = displayed;
    this._broadcastEvent(this.EVENTS.STATUS_DISPLAYED_CHANGED, { displayed });
  };

  public isEditing = () => {
    return this.editing;
  };

  public setEditing = (editing: boolean) => {
    this.editing = editing;
    this._broadcastEvent(this.EVENTS.STATUS_EDITING_CHANGED, { editing });
  };

  public isProcessing = () => {
    return this.processing;
  };

  public getPanoramicState = (displaySetUID: string) => {
    return this.panoramicStates[displaySetUID];
  };

  public setPanoramicState = (displaySetInstanceUID: string, panoramicState: PanoramicState) => {
    this.panoramicStates[displaySetInstanceUID] = panoramicState;
    this._broadcastEvent(this.EVENTS.PANORAMIC_STATE_UPDATED, { displaySetInstanceUID });
  };

  public setDentascanIndex = (displaySetInstanceUID: string, dentascanIndex: number) => {
    this.dentascanIndex = dentascanIndex;
    this._broadcastEvent(this.EVENTS.DENTASCAN_INDEX_UPDATED, { displaySetInstanceUID });
  };

  public getComment = () => {
    return this.comment;
  };

  public setComment = (comment: string) => {
    const { databaseService } = this.servicesManager.services;
    databaseService.modifyAnalysisExamIndication(comment);
    this.comment = comment;
  };

  public setTeethAxes = (displaySetInstanceUID: string, teethAxes: PanoramicState['teethAxes']) => {
    this.panoramicStates[displaySetInstanceUID].teethAxes = teethAxes;
    this._broadcastEvent(this.EVENTS.TEETH_AXES_UPDATED, { displaySetInstanceUID });
  };

  public setPanoramicProcessingPourcent = (percent: number) => {
    this._broadcastEvent(this.EVENTS.PANORAMIC_PROCESSING, { percent });
  };

  // -------------------- PANORAMIC CALCULATION -------------------- //

  public _getImageId = (displaySetUID: string) => {
    const { displaySetService } = this.servicesManager.services;

    const displaySet = displaySetService.getDisplaySetByUID(displaySetUID);

    // Get volume from where we want to compute panoramic on
    const baseVolumeSeries = DicomMetadataStore.getSeries(
      displaySet.StudyInstanceUID,
      displaySet.SeriesInstanceUID
    );
    const frameNumber = baseVolumeSeries.instances[0].frameNumber;
    const baseId =
      baseVolumeSeries.instances[0].imageId + (frameNumber ? '&frame=' + frameNumber : '');

    return baseId;
  };

  // -------------------- PANORAMIC PANEL -------------------- //

  public initializePanoramicService = () => {
    const { hangingProtocolService, viewportGridService } = this.servicesManager.services;

    const displaySetUID = viewportGridService.getDisplaySetsUIDsForViewport('axial')[0];
    this.setPanoramicState(displaySetUID, undefined);

    // Protocol listeners
    const protocolEvent = hangingProtocolService.EVENTS.PROTOCOL_CHANGED;
    hangingProtocolService.subscribe(protocolEvent, ({ protocol }) => {
      if (protocol.id === 'panoramicView' && !this.isDisplayed()) {
        this.handleProtocolEnter(displaySetUID);
      } else if (protocol.id !== 'panoramicView' && this.isDisplayed()) {
        this.handleProtocolExit(displaySetUID);
      }
    });

    generatePanoramic(this.servicesManager);
  };

  public showOrHideAnnotations = (annotationUIDs: string[], visible: boolean) => {
    for (const annotationUID of annotationUIDs) {
      cstAnnotation.visibility.setAnnotationVisibility(annotationUID, visible);
    }
    cstUtils.triggerAnnotationRenderForViewportIds(['axial']);
  };

  public initDisplay = async (displaySetUID: string) => {
    const panoramicState = this.getPanoramicState(displaySetUID);

    await this.waitDisplaySets();
    this.commandsManager.runCommand('panoramicView', { reset: true });

    // Enable annotations on panoramic protocol
    const annotationUIDs = this.isEditing()
      ? [panoramicState.annotationUIDs[0]]
      : panoramicState.annotationUIDs?.slice(1);
    this.showOrHideAnnotations(annotationUIDs, true);
    await this.waitPanoramicDisplay();

    // Update dentascans segmentations
    await this.initializeDentascanSegmentations();

    // Triggers renderPanoramicAnnotation
    const panoramicWidth = panoramicState.dentascans.length;
    const dentascanIndex = Math.round(panoramicWidth / 2) - 1;
    this.setDentascanIndex(displaySetUID, dentascanIndex);
  };

  public handleProtocolEnter = async (displaySetUID: string) => {
    const { cornerstoneViewportService, hangingProtocolService } = this.servicesManager.services;

    // Ensure listeners are not added before dentascan viewports are accessible
    const nbExpectedViewports =
      hangingProtocolService.getActiveProtocol().viewportMatchDetails.size;
    await waitCondition(
      () => cornerstoneViewportService.getViewportIds().length === nbExpectedViewports
    );
    await waitCondition(
      () => cornerstoneViewportService.getRenderingEngine()._needsRender.size === 0
    );

    this.setDisplayed(true);
    this.addSubscriptions();
    this.addViewportListeners();
    this.initDisplay(displaySetUID);
  };

  public handleProtocolExit = async (displaySetUID: string) => {
    // Disable annotations on other protocols
    const panoramicState = this.getPanoramicState(displaySetUID);
    if (panoramicState) {
      this.showOrHideAnnotations(panoramicState.annotationUIDs, false);
    }
    this.removeViewportListeners();
    for (const unsub of this.subscriptions) {
      unsub();
    }
    this.subscriptions = [];
    this.setDisplayed(false);
  };

  public createDentascanSegmentation = async (
    segmentation: cstTypes.Segmentation,
    dentascanDisplaySet: OhifTypes.DisplaySet
  ) => {
    const { segmentationService } = this.servicesManager.services;
    const { segmentationId, segments, label } = segmentation;
    const dentascanSegId = 'dentascan_' + segmentationId;

    // Delete former dentascan segmentations
    if (segmentationService.getSegmentation(dentascanSegId)) {
      segmentationService.remove(dentascanSegId);
    }
    await segmentationService.createLabelmapForDisplaySet(dentascanDisplaySet, {
      segmentationId: dentascanSegId,
      segments,
      label,
    });
  };

  public createDentascanSegRepresentations = async (segmentation: cstTypes.Segmentation) => {
    const { cornerstoneViewportService, segmentationService } = this.servicesManager.services;
    const { segmentationId, segments } = segmentation;
    const dentascanSegId = 'dentascan_' + segmentationId;

    const colorLUTIndex = segmentationService._segmentationIdToColorLUTIndexMap.get(segmentationId);
    segmentationService._segmentationIdToColorLUTIndexMap.set(dentascanSegId, colorLUTIndex);

    // TODO Find better way to copy segment visibility
    const pulpSegment = Object.values(segments).find(segment => segment?.label === 'Pulp');
    for (const viewportId of [
      'dentascan-3',
      'dentascan-2',
      'dentascan-1',
      'dentascan',
      'dentascan1',
      'dentascan2',
      'dentascan3',
    ]) {
      if (!cornerstoneViewportService.getViewportIds().includes(viewportId)) {
        continue;
      }
      await segmentationService.addSegmentationRepresentation(viewportId, {
        segmentationId: dentascanSegId,
        type: cstEnums.SegmentationRepresentations.Labelmap,
      });
      if (pulpSegment) {
        const { segmentIndex } = pulpSegment;
        segmentationService.setSegmentVisibility(viewportId, dentascanSegId, segmentIndex, false);
      }
      segmentationService.setActiveSegmentation(viewportId, dentascanSegId);
    }
  };

  public copySegmentationVolumeForDentascan = (segmentationId: string) => {
    const { segmentationService, cornerstoneViewportService } = this.servicesManager.services;

    const { displaySetInstanceUID, volume } = cornerstoneViewportService
      .getViewportInfo('axial')
      .getViewportData().data[0] as VolumeData;
    const [volumeWidth, volumeHeight, nbLayers] = volume.dimensions;
    const { dentascansDimensions, minMaxLayer, minPoints, normals } =
      this.getPanoramicState(displaySetInstanceUID);
    const [nbDentascans, dentascanWidth, dentascanHeight] = dentascansDimensions;
    const minLayer: number = minMaxLayer[0];

    const getPixel = (
      minX: number,
      minY: number,
      vxNormal: number,
      vyNormal: number,
      dentascanK: number
    ) => {
      const xi = minX + dentascanK * vxNormal;
      const yi = minY + dentascanK * vyNormal;
      const xj = minX + (dentascanK + 1) * vxNormal;
      const yj = minY + (dentascanK + 1) * vyNormal;
      const [pxi, pxj, pyi, pyj] = [Math.floor(xi), Math.floor(xj), Math.floor(yi), Math.floor(yj)];
      if (xi < 0 || yi < 0 || xj >= volumeWidth || yj >= volumeHeight) {
        return {};
      }

      // Same pixel
      let px = pxi;
      let py = pyi;
      if (pxi !== pxj && pyi === pyj) {
        // Compare with pixel at x + 1
        const tx = pxi < pxj ? (1 - (xi % 1)) / vxNormal : -(xi % 1) / vxNormal; // Ratio of segment within pxi
        if (tx >= 0.5) {
          px = pxj;
        }
      } else if (pxi === pxj && pyi !== pyj) {
        // Compare with pixel at y + 1
        const ty = pyi < pyj ? (1 - (yi % 1)) / vyNormal : -(yi % 1) / vyNormal; // Ratio of segment within pyi
        if (ty >= 0.5) {
          py = pyj;
        }
      } else if (pxi !== pxj && pyi !== pyj) {
        // Compare with both pixels
        const tx = pxi < pxj ? (1 - (xi % 1)) / vxNormal : -(xi % 1) / vxNormal;
        const ty = pyi < pyj ? (1 - (yi % 1)) / vyNormal : -(yi % 1) / vyNormal;
        if (tx < ty) {
          if (ty <= 0.5) {
            // Take the edge voxel if it is in 50% of the segment or more
            px = pxj;
            py = pyj;
          } else if (tx < 0.5) {
            // Take the middle voxel otherwise
            px = pxj;
          }
        } else {
          if (tx <= 0.5) {
            px = pxj;
            py = pyj;
          } else if (ty < 0.5) {
            py = pyj;
          }
        }
      }
      return { px, py };
    };

    // TODO Ensure derived labelmap volume is already created from labelmap images
    const { voxelManager: segVoxelManager } = segmentationService.getLabelmapVolume(segmentationId);
    const segScalarData = segVoxelManager.getCompleteScalarDataArray();
    const dentascanSegId = 'dentascan_' + segmentationId;
    const { voxelManager: dentascanSegVoxelManager } =
      segmentationService.getLabelmapVolume(dentascanSegId);
    const dentascanSegScalarData = dentascanSegVoxelManager.getCompleteScalarDataArray().slice();

    // Replace values of current scalar data
    for (let i = 0; i < nbDentascans; i++) {
      const [minX, minY] = minPoints[i];
      const [vxNormal, vyNormal] = normals[i];
      const dentascanOffset = i * dentascanWidth * dentascanHeight;

      for (let dentascanK = 0; dentascanK < dentascanWidth; dentascanK++) {
        const { px, py } = getPixel(minX, minY, vxNormal, vyNormal, dentascanK);
        if (px === undefined) {
          continue;
        }

        for (let layer = 0; layer < dentascanHeight; layer++) {
          const dentascansIndex = dentascanOffset + layer * dentascanWidth + dentascanK;
          const volumeLayer = minLayer + (dentascanHeight - layer - 1);
          const volumeIndex = volumeLayer * volumeWidth * volumeHeight + py * volumeWidth + px;
          dentascanSegScalarData[dentascansIndex] = segScalarData[volumeIndex];
        }
      }
    }
    dentascanSegVoxelManager.setCompleteScalarDataArray(dentascanSegScalarData);
    cstSegmentation.triggerSegmentationEvents.triggerSegmentationDataModified(dentascanSegId);
  };

  // Create dentascan segmentation when panoramic is created
  public initializeDentascanSegmentations = async (
    segmentations: cstTypes.Segmentation[] = undefined
  ) => {
    const { displaySetService, segmentationService } = this.servicesManager.services;

    const axialSegmentations: cstTypes.Segmentation[] =
      segmentations ?? segmentationService.getAxialSegmentations();
    if (!axialSegmentations?.length) {
      // No segmentation found
      return;
    }

    // Initialize dentascan segmentations
    const dentascanDisplaySet: OhifTypes.DisplaySet = displaySetService
      .getActiveDisplaySets()
      .find(displaySet => displaySet.SeriesInstanceUID.includes('dentascan'));
    await Promise.all(
      axialSegmentations.map(async segmentation => {
        await this.createDentascanSegmentation(segmentation, dentascanDisplaySet);
        await this.createDentascanSegRepresentations(segmentation);
        await this.copySegmentationVolumeForDentascan(segmentation.segmentationId);
      })
    );
  };

  protected getDentascanPointIndex = (evt: EventTypes.InteractionEventType) => {
    const { element: dentascanElement, currentPoints } = evt.detail;
    const { viewport: dentascanViewport } = getEnabledElement(dentascanElement);

    // Convert points from dentascan coordinates to axial coordinates
    const { imageData: dentascanImageData } = dentascanViewport.getImageData();
    const [dentascanK, layer, i] = dentascanImageData.worldToIndex(currentPoints.world) as Point3;
    // 0.5 are added to dentascanK and layer as top-left index coordinates are [-0.5, -0.5]
    // i is rounded because dentascan is set isotropic while it may slightly differ on z axis

    return [dentascanK + 0.5, layer + 0.5, Math.round(i)];
  };

  protected getAxialPointIndex = (
    panoramicState: PanoramicState,
    dentascanK: number,
    layer: number,
    i: number
  ) => {
    // Dentascan pixels are obtained with the average value of two voxels from the dentascan segment
    // As the opposite operation cannot be done, we place the cursor at the corresponding coordinates
    // along the dentascan segment (float), instead of rounding to closer voxel
    const { minMaxLayer, dentascansDimensions, minPoints, normals } = panoramicState;
    const minLayer = minMaxLayer[0];
    const [nbDentascans, dentascanWidth, dentascanHeight] = dentascansDimensions;
    const [minX, minY] = minPoints[i];
    const [vxNormal, vyNormal] = normals[i];

    const x = minX + dentascanK * vxNormal;
    const y = minY + dentascanK * vyNormal;
    const z = minLayer + (dentascanHeight - layer - 1);

    return [x, y, z];
  };

  protected getAxialOperationData = (
    evt: EventTypes.InteractionEventType,
    brushInstance: BrushTool,
    segmentIndex: number
  ) => {
    const { cornerstoneViewportService, segmentationService } = this.servicesManager.services;

    // Code modified from BrushTool.ts
    const axialViewport = cornerstoneViewportService.getCornerstoneViewport('axial');
    const axialElement = axialViewport.element;

    const axialViewportInfo = cornerstoneViewportService.getViewportInfo('axial');
    const axialVolumeData = axialViewportInfo.getViewportData().data[0] as VolumeData;
    const axialImageData = axialVolumeData.volume.imageData;

    const displaySetUID = axialVolumeData.displaySetInstanceUID;
    const panoramicState = this.getPanoramicState(displaySetUID);
    // dentascanK and layer are float, i is integer
    const [dentascanK, layer, i] = this.getDentascanPointIndex(evt);
    const [x, y, z] = this.getAxialPointIndex(panoramicState, dentascanK, layer, i) as Point3;
    const axialCenterCursorInWorld = axialImageData.indexToWorld([x, y, z]);

    // Reset _hoverData for calculating cursor
    brushInstance._hoverData = brushInstance.createHoverData(axialElement);
    brushInstance._calculateCursor(axialElement, axialCenterCursorInWorld);
    const { points } = brushInstance._hoverData.brushCursor.data.handles;

    const editData = brushInstance.createEditData(axialElement);
    const { preview, strategySpecificConfiguration, eraseFocusIndex } = brushInstance.configuration;
    // TODO viewPlaneNormal and viewUp can be retrieved because default viewport and dentascans are axial
    const { viewPlaneNormal, viewUp } = axialViewport.getCamera();
    const toolGroupId = 'mpr';
    const { segmentationId } = segmentationService.getActiveSegmentation('axial');

    const operationData = {
      ...editData,
      points,
      segmentIndex,
      previewColors: preview.enabled ? preview.previewColors : null,
      viewPlaneNormal,
      toolGroupId,
      segmentationId,
      viewUp,
      strategySpecificConfiguration,
      eraseFocusIndex,
      // Provide the preview information so that data can be used directly
      preview: brushInstance._previewData?.preview,
    };

    return operationData;
  };

  private _downCallBack = (evt: EventTypes.InteractionEventType) => {
    const { toolGroupService } = this.servicesManager.services;
    const { viewportId, element, mouseButton } = evt.detail;

    // Add listener on MouseUp/MouseClick for segmentation on axial viewport
    // Add listener on MouseDrag and MouseUp/MouseClick for segmentation on each dentascan viewport
    const toolGroupId = 'mpr';
    const toolGroup = toolGroupService.getToolGroup(toolGroupId) as cstTypes.IToolGroup;
    const toolName = toolGroup.currentActivePrimaryToolName;
    if (mouseButton === 1 && (toolName.includes('Brush') || toolName.includes('Eraser'))) {
      // Left button down and CircularBrush/SphereBrush/CircularEraser/SphereEraser
      if (viewportId !== 'axial') {
        element.addEventListener(cstEnums.Events.MOUSE_DRAG, this._dragCallBack as EventListener);
      }
      element.addEventListener(cstEnums.Events.MOUSE_UP, this._endCallBack as EventListener);
      element.addEventListener(cstEnums.Events.MOUSE_CLICK, this._endCallBack as EventListener);
    }
  };

  private _endCallBack = (evt: EventTypes.InteractionEventType) => {
    const { segmentationService } = this.servicesManager.services;

    const { viewportId, element } = evt.detail;
    if (viewportId !== 'axial') {
      element.removeEventListener(cstEnums.Events.MOUSE_DRAG, this._dragCallBack as EventListener);
    }
    element.removeEventListener(cstEnums.Events.MOUSE_UP, this._endCallBack as EventListener);
    element.removeEventListener(cstEnums.Events.MOUSE_CLICK, this._endCallBack as EventListener);

    const segmentation = segmentationService.getActiveSegmentation('axial');
    this.copySegmentationVolumeForDentascan(segmentation.segmentationId);
  };

  private _dragCallBack = (evt: EventTypes.InteractionEventType) => {
    const { cornerstoneViewportService, segmentationService, toolGroupService } =
      this.servicesManager.services;

    const toolGroupId = 'mpr';
    const toolGroup = toolGroupService.getToolGroup(toolGroupId) as cstTypes.IToolGroup;
    const brushInstance = toolGroup.getToolInstance(toolGroup.currentActivePrimaryToolName);

    const { segmentIndex } = segmentationService.getActiveSegment('dentascan');
    const axialOperationData = this.getAxialOperationData(evt, brushInstance, segmentIndex);

    const axialElement = cornerstoneViewportService.getCornerstoneViewport('axial').element;
    const axialEnabledElement = getEnabledElement(axialElement);
    brushInstance.applyActiveStrategy(axialEnabledElement, axialOperationData);
  };

  public deletePanoramicAnnotation = () => {
    const { measurementService, toolGroupService } = this.servicesManager.services;

    //============================= DELETE ALL PREVIOUS DENTASCAN ANNOTATIONS =================//
    const toolGroup = toolGroupService.getToolGroupForViewport('panoramic') as cstTypes.IToolGroup;
    const lineSegmentInstance = toolGroup.getToolInstance('LineSegment');

    const dentascanMeasurements = measurementService.getMeasurements().filter(m => {
      return m.toolName === 'LineSegment';
    });
    for (const dm of dentascanMeasurements) {
      if (dm.metadata.dentascan) {
        this.commandsManager.runCommand('deleteMeasurement', { uid: dm.uid });
        lineSegmentInstance.removeLineSegmentAnnotation(dm.uid);
      }
    }
  };

  private _addDiseaseAnnotation = (
    viewport: StackViewport,
    translation: JsonTranslation,
    subtype: string,
    x: number,
    y: number,
    w: number,
    h: number
  ) => {
    const camera = viewport.getCamera();
    const { viewPlaneNormal, viewUp } = camera;
    const FrameOfReferenceUID = viewport.getFrameOfReferenceUID();
    const { imageData } = viewport.getImageData();
    const tl = imageData.indexToWorld([x, y, 0]);
    const tr = imageData.indexToWorld([x + w, y, 0]);
    const bl = imageData.indexToWorld([x, y + h, 0]);
    const br = imageData.indexToWorld([x + w, y + h, 0]);
    const referencedImageId = viewport.getViewReferenceId().split('imageId:')[1];
    const annotation = {
      invalidated: true,
      highlighted: false,
      metadata: {
        toolName: 'Disease',
        viewPlaneNormal: [...viewPlaneNormal] as Point3,
        viewUp: [...viewUp] as Point3,
        FrameOfReferenceUID,
        referencedImageId,
        ...viewport.getViewReference({ points: [tl as Point3] }),
      },
      data: {
        label: translation.EN, // TODO threshold specific optimal sensible
        subtype,
        handles: {
          points: [[...tl] as Point3, [...tr] as Point3, [...bl] as Point3, [...br] as Point3],
          activeHandleIndex: null,
        },
        textbox: {},
        cachedStats: {},
      },
      annotationUID: csUtils.uuidv4(),
    };
    cstAnnotation.state.addAnnotation(annotation, viewport.element);

    return annotation;
  };

  public generateNewPanoramicAnnotation = (
    displaySetUID: string,
    panoramicViewport: StackViewport
  ) => {
    const { toolGroupService } = this.servicesManager.services;

    const toolGroup = toolGroupService.getToolGroupForViewport('panoramic') as cstTypes.IToolGroup;
    if (!toolGroup) {
      return;
    }

    // Add LineSegment annotation indicating dentascan section on panoramic
    const lineSegmentInstance = toolGroup.getToolInstance('LineSegment');
    const panoramicState = this.getPanoramicState(displaySetUID);
    const [nbDentascans, dentascanWidth, dentascanHeight] = panoramicState.dentascansDimensions;
    const [yMin, yMax] = [0, dentascanHeight - 1];
    const { imageData } = panoramicViewport.getImageData();
    const top = imageData.indexToWorld([this.dentascanIndex, yMin, 0]);
    const bottom = imageData.indexToWorld([this.dentascanIndex, yMax, 0]);
    lineSegmentInstance.addNewAnnotationWithMode(
      panoramicViewport.element,
      [top, bottom],
      'dentascan',
      'rgb(255, 255, 255)'
    );
  };

  public generateDiseaseAnnotations = (displaySetUID: string, panoramicViewport: StackViewport) => {
    const annotations = cstAnnotation.state.getAnnotations('Disease', panoramicViewport.element);
    if (annotations.length > 0) {
      return;
    }

    const panoramicState = this.getPanoramicState(displaySetUID);
    if (panoramicState.diseases) {
      // Add Disease annotation indicating bounding boxes of diseases on panoramic
      for (const disease of panoramicState.diseases) {
        // Display only: LIPOE, Kyste, Polype (Opacité sinusiale)
        if (['10', '89', '120'].includes(disease.subtype)) {
          const { pos, subtype } = disease;
          const { show_on_image, translation } = panoramicState.diseasesCategories[subtype];
          if (show_on_image) {
            const { x, y, width, height } = pos;
            this._addDiseaseAnnotation(
              panoramicViewport,
              translation,
              subtype,
              x,
              y,
              width,
              height
            );
          }
        }
      }
    }
  };

  public displayDentascans = () => {
    const { cornerstoneViewportService } = this.servicesManager.services;

    //================== DISPLAY WANTED DENTASCANS IN BOTTOM VIEWPORT ===========================//
    const viewportIds = cornerstoneViewportService.getViewportIds();
    const nbDentascanViewports = viewportIds.length - 2;
    if (nbDentascanViewports > 0) {
      const middleDentascanViewportIndex = Math.floor(nbDentascanViewports / 2);
      for (let i = 0; i < nbDentascanViewports; i++) {
        const { element } = cornerstoneViewportService.getCornerstoneViewport(viewportIds[i + 2]);
        // We also display the dentascans before and after the main one
        csUtils.jumpToSlice(element, {
          imageIndex: this.dentascanIndex + (i - middleDentascanViewportIndex) * 2,
          debounceLoading: true,
        });
      }
    }
  };

  public addSubscriptions = () => {
    const eventDentascanIndex = this.EVENTS.DENTASCAN_INDEX_UPDATED;
    const { unsubscribe } = this.subscribe(eventDentascanIndex, ({ displaySetInstanceUID }) => {
      this.renderPanoramicAnnotation(displaySetInstanceUID);
    });
    this.subscriptions.push(unsubscribe);
  };

  public addViewportListeners = () => {
    const { cornerstoneViewportService } = this.servicesManager.services;

    const { element } = cornerstoneViewportService.getCornerstoneViewport('axial');
    element.addEventListener(cstEnums.Events.MOUSE_DOWN, this._downCallBack as EventListener);
    const viewportIds = cornerstoneViewportService.getViewportIds();
    for (let i = 2; i < viewportIds.length; i++) {
      const { element } = cornerstoneViewportService.getCornerstoneViewport(viewportIds[i]);
      element.addEventListener(cstEnums.Events.MOUSE_DOWN, this._downCallBack as EventListener);
    }
  };

  public removeViewportListeners = () => {
    const { cornerstoneViewportService } = this.servicesManager.services;

    const { element } = cornerstoneViewportService.getCornerstoneViewport('axial');
    element.removeEventListener(cstEnums.Events.MOUSE_DOWN, this._downCallBack as EventListener);
  };

  public renderPanoramicAnnotation = async (displaySetUID: string) => {
    const { cornerstoneViewportService, hangingProtocolService } = this.servicesManager.services;

    await waitCondition(
      () => cornerstoneViewportService.getRenderingEngine()._needsRender.size === 0
    );

    const nbExpectedViewports =
      hangingProtocolService.getActiveProtocol().viewportMatchDetails.size;
    await waitCondition(
      () => cornerstoneViewportService.getViewportIds().length === nbExpectedViewports
    );

    const panoramicViewport = cornerstoneViewportService.getCornerstoneViewport(
      'panoramic'
    ) as StackViewport;
    if (panoramicViewport) {
      this.deletePanoramicAnnotation();
      // TODO maybe move annotation instead of delete + generate
      this.generateNewPanoramicAnnotation(displaySetUID, panoramicViewport);
      this.generateDiseaseAnnotations(displaySetUID, panoramicViewport);
      this.displayDentascans();
    }
  };

  public waitDisplaySets = async () => {
    const { displaySetService } = this.servicesManager.services;

    // Wait until displaySet is updated
    await waitCondition(() => {
      const activeDisplaySets = displaySetService.getActiveDisplaySets();
      return (
        activeDisplaySets.some(displaySet => displaySet.SeriesInstanceUID.includes('panoramic')) &&
        activeDisplaySets.some(displaySet => displaySet.SeriesInstanceUID.includes('dentascan'))
      );
    });
  };

  public waitPanoramicDisplay = async () => {
    const { cornerstoneViewportService, displaySetService, viewportGridService } =
      this.servicesManager.services;

    // Previous call to waitDisplaySets ensures newPanoramicDisplaySet is not empty
    const newPanoramicDisplaySet = displaySetService
      .getActiveDisplaySets()
      .find(displaySet => displaySet.SeriesInstanceUID.includes('panoramic'));

    // Wait until viewportGrid is updated
    await waitCondition(
      () =>
        newPanoramicDisplaySet.displaySetInstanceUID ===
        viewportGridService.getDisplaySetsUIDsForViewport('panoramic')?.[0]
    );

    // Wait until imageData is set
    await waitCondition(() =>
      cornerstoneViewportService.getCornerstoneViewport('panoramic').getImageData()
    );
  };
}
