import { PubSubService } from '@ohif/core';
import axios from 'axios';
import { NumberPair, Points, Position } from '../../types/Panoramic';

interface ResultInfo3d {
  id?: number;
  analyze_id?: number;
  segmented_anatomy?: ArrayLike<number>;
  segmented_diseases?: ArrayLike<number>;
  panoramic?: Float32Array;
  diseases: { pos: Position; subtype: string; confidence: number }[];
  metadata: {
    dentascan_thickness: number;
    min_max_tissue_layer: NumberPair;
    points: Points;
  };
  teeth_axes: { [tooth: string]: number[] };
}

interface ResultInfoFull {
  id?: number;
  image_id: number;
  date: string;
  api_version: string;
  app_version: string;
  analyze_uuid: string;
  status: 'ANALYSED' | 'IN_PROGRESS' | 'VALIDATED';
  examIndication: string;
  type: number;
  data3d: ResultInfo3d;
}

export default class DatabaseService extends PubSubService {
  private connectionString: string = '';
  private imageId: number = -1;
  private analysisId: number = -1;

  static EVENTS = {};

  public static REGISTRATION = {
    name: 'databaseService',
    create: (): DatabaseService => {
      return new DatabaseService();
    },
  };

  constructor() {
    super(DatabaseService.EVENTS);
  }

  public setConnectionString = (connectionString: string) => {
    this.connectionString = connectionString;
  };

  public getConnectionString = () => {
    return this.connectionString;
  };

  public setImageId = (imageId: number) => {
    this.imageId = imageId;
  };

  public getImageId = () => {
    return this.imageId;
  };

  public setAnalysisId = (analysisId: number) => {
    this.analysisId = analysisId;
  };

  public getAnalysisId = () => {
    return this.analysisId;
  };

  private isValidAnalysis = (): boolean => {
    return this.connectionString !== '' && this.analysisId !== -1;
  };

  public getImageContentById = async (): Promise<string | null> => {
    if (this.connectionString === '' || this.imageId === -1) {
      return null;
    }

    try {
      const response = await axios.get(this.connectionString + `/image/${this.imageId}`);
      return response.data.data;
    } catch (e) {
      throw new Error(`Error in getImageContentById: ${e}`);
    }
  };

  public createAnalysis = async (analysisUuid: string): Promise<boolean | null> => {
    if (this.connectionString === '' || this.imageId === -1) {
      return null;
    }

    const emptyAnalysis: ResultInfoFull = {
      image_id: this.imageId,
      date: new Date().toISOString(),
      api_version: '1.1.0',
      app_version: '1.0.1',
      analyze_uuid: analysisUuid,
      status: 'ANALYSED',
      examIndication: '',
      type: 3,
      data3d: {
        diseases: [],
        metadata: {
          dentascan_thickness: 0,
          min_max_tissue_layer: [0, 0],
          points: {
            controlPoints: [],
            curvePoints: [],
            innerPoints: [],
            normals: [],
            outerPoints: [],
          },
        },
        teeth_axes: {},
      },
    };

    try {
      const response = await axios.post(this.connectionString + '/analyze', emptyAnalysis);
      if (!response.data) {
        return false;
      }

      this.analysisId = (await this.getAnalysisByImageId()).id;
      return response.data === 'success';
    } catch (e) {
      throw new Error(`Error in createAnalysis: ${e}`);
    }
  };

  public updateImageDescription = async (description: string): Promise<boolean | null> => {
    if (!this.isValidAnalysis()) {
      return null;
    }

    try {
      const response = await axios.patch(
        this.connectionString + `/image/${this.analysisId}/description`,
        { description }
      );
      if (!response.data) {
        return false;
      }
      return response.data.status === 'success';
    } catch (e) {
      throw new Error(`Error in updateImageDescription: ${e}`);
    }
  };

  public modifyAnalysisSegmentedAnatomy = async (
    segmented_anatomy: ArrayLike<number>
  ): Promise<boolean | null> => {
    if (!this.isValidAnalysis()) {
      return null;
    }

    try {
      const response = await axios.post(
        this.connectionString + `/analyze/${this.analysisId}/segmented_anatomy`,
        segmented_anatomy,
        { headers: { 'Content-Type': 'application/octet-stream' } }
      );
      return response.data?.status === 'success';
    } catch (e) {
      throw new Error(`Error in modifyAnalysisSegmentedAnatomy: ${e}`);
    }
  };

  public modifyAnalysisSegmentedDiseases = async (
    segmented_diseases: ArrayLike<number>
  ): Promise<boolean | null> => {
    if (!this.isValidAnalysis()) {
      return null;
    }

    try {
      const response = await axios.post(
        this.connectionString + `/analyze/${this.analysisId}/segmented_diseases`,
        segmented_diseases,
        { headers: { 'Content-Type': 'application/octet-stream' } }
      );
      return response.data?.status === 'success';
    } catch (e) {
      throw new Error(`Error in modifyAnalysisSegmentedDiseases: ${e}`);
    }
  };

  public modifyAnalysisPanoramic = async (panoramic: Float32Array): Promise<boolean | null> => {
    if (!this.isValidAnalysis()) {
      return null;
    }

    try {
      const response = await axios.post(
        this.connectionString + `/analyze/${this.analysisId}/panoramic`,
        panoramic,
        { headers: { 'Content-Type': 'application/octet-stream' } }
      );
      return response.data?.status === 'success';
    } catch (e) {
      throw new Error(`Error in modifyAnalysisPanoramic: ${e}`);
    }
  };

  public modifyAnalysisDiseases = async (
    diseases: ResultInfo3d['diseases']
  ): Promise<boolean | null> => {
    if (!this.isValidAnalysis()) {
      return null;
    }

    try {
      const response = await axios.post(
        this.connectionString + `/analyze/${this.analysisId}/diseases`,
        { diseases }
      );
      return response.data?.status === 'success';
    } catch (e) {
      throw new Error(`Error in modifyAnalysisDiseases: ${e}`);
    }
  };

  public modifyAnalysisMetadata = async (
    metadata: ResultInfo3d['metadata']
  ): Promise<boolean | null> => {
    if (!this.isValidAnalysis()) {
      return null;
    }

    try {
      const response = await axios.post(
        this.connectionString + `/analyze/${this.analysisId}/metadata`,
        { metadata }
      );
      return response.data?.status === 'success';
    } catch (e) {
      throw new Error(`Error in modifyAnalysisMetadata: ${e}`);
    }
  };

  public modifyAnalysisTeethAxes = async (
    teeth_axes: ResultInfo3d['teeth_axes']
  ): Promise<boolean | null> => {
    if (!this.isValidAnalysis()) {
      return null;
    }

    try {
      const response = await axios.post(
        this.connectionString + `/analyze/${this.analysisId}/teeth_axes`,
        { teeth_axes }
      );
      return response.data?.status === 'success';
    } catch (e) {
      throw new Error(`Error in modifyAnalysisTeethAxes: ${e}`);
    }
  };

  public modifyAnalysisStatus = async (
    status: ResultInfoFull['status']
  ): Promise<boolean | null> => {
    if (!this.isValidAnalysis()) {
      return null;
    }

    try {
      const response = await axios.post(
        this.connectionString + `/analyze/${this.analysisId}/status`,
        { status }
      );
      if (!response.data) {
        return false;
      }
      return response.data === 'success';
    } catch (e) {
      throw new Error(`Error in modifyAnalysisStatus: ${e}`);
    }
  };

  public modifyAnalysisExamIndication = async (examIndication: string): Promise<boolean | null> => {
    if (!this.isValidAnalysis()) {
      return null;
    }

    try {
      const response = await axios.post(
        this.connectionString + `/analyze/${this.analysisId}/examIndication`,
        { examIndication }
      );
      if (!response.data) {
        return false;
      }
      return response.data === 'success';
    } catch (e) {
      throw new Error(`Error in modifyAnalysisExamIndication: ${e}`);
    }
  };

  public getAnalysisById = async (): Promise<ResultInfoFull | null> => {
    if (!this.isValidAnalysis()) {
      return null;
    }

    try {
      const response = await axios.get(this.connectionString + `/analyze/${this.analysisId}`);
      return response.data.data;
    } catch (e) {
      throw new Error(`Error in getAnalysisById: ${e}`);
    }
  };

  public getAnalysisByImageId = async (): Promise<ResultInfoFull | null> => {
    if (this.connectionString === '' || this.imageId === -1) {
      return null;
    }

    try {
      const response = await axios.get(this.connectionString + `/analyze/image/${this.imageId}`);
      this.analysisId = response.data.data.id;
      return response.data.data;
    } catch (e) {
      throw new Error(`Error in getAnalysisByImageId: ${e}`);
    }
  };
}
